import{c as e,Q as a,j as n,m as l}from"./chunks/framework.rlpw0eGz.js";const y=JSON.parse('{"title":"Waybeam venc — Відеоенкодер для FPV","description":"Огляд waybeam venc — автономного H.265/H.264 відеоенкодера та стрімера для FPV-систем на базі SigmaStar Infinity6E та Infinity6C.","frontmatter":{"title":"Waybeam venc — Відеоенкодер для FPV","description":"Огляд waybeam venc — автономного H.265/H.264 відеоенкодера та стрімера для FPV-систем на базі SigmaStar Infinity6E та Infinity6C.","head":[["link",{"rel":"canonical","href":"https://openfpv.com.ua/software/waybeam-venc"}],["link",{"rel":"alternate","hreflang":"uk","href":"https://openfpv.com.ua/software/waybeam-venc"}],["link",{"rel":"alternate","hreflang":"en","href":"https://openfpv.com.ua/en/software/waybeam-venc"}],["link",{"rel":"alternate","hreflang":"x-default","href":"https://openfpv.com.ua/software/waybeam-venc"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:url","content":"https://openfpv.com.ua/software/waybeam-venc"}],["meta",{"property":"og:title","content":"Waybeam venc — Відеоенкодер для FPV"}],["meta",{"property":"og:description","content":"Огляд waybeam venc — автономного H.265/H.264 відеоенкодера та стрімера для FPV-систем на базі SigmaStar Infinity6E та Infinity6C."}],["meta",{"property":"og:image","content":"https://openfpv.com.ua/og-software.png"}],["meta",{"property":"og:locale","content":"uk_UA"}],["meta",{"property":"og:locale:alternate","content":"en_US"}],["meta",{"name":"twitter:image","content":"https://openfpv.com.ua/og-software.png"}],["meta",{"name":"twitter:title","content":"Waybeam venc — Відеоенкодер для FPV"}],["meta",{"name":"twitter:description","content":"Огляд waybeam venc — автономного H.265/H.264 відеоенкодера та стрімера для FPV-систем на базі SigmaStar Infinity6E та Infinity6C."}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@graph\\":[{\\"@type\\":\\"Organization\\",\\"@id\\":\\"https://openfpv.com.ua/#org\\",\\"name\\":\\"OpenFPV Ukraine\\",\\"url\\":\\"https://openfpv.com.ua\\",\\"logo\\":\\"https://openfpv.com.ua/logo-light.png\\",\\"sameAs\\":[\\"https://github.com/Maxwell456/openipc-docs-ukr\\"]},{\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Головна\\",\\"item\\":\\"https://openfpv.com.ua/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Програмне забезпечення\\",\\"item\\":\\"https://openfpv.com.ua/software/apfpv\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Waybeam venc — Відеоенкодер для FPV\\"}]},{\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"Waybeam venc — Відеоенкодер для FPV\\",\\"description\\":\\"Огляд waybeam venc — автономного H.265/H.264 відеоенкодера та стрімера для FPV-систем на базі SigmaStar Infinity6E та Infinity6C.\\",\\"inLanguage\\":\\"uk-UA\\",\\"url\\":\\"https://openfpv.com.ua/software/waybeam-venc\\",\\"image\\":\\"https://openfpv.com.ua/og-software.png\\",\\"dateModified\\":\\"2026-05-31T11:48:56.000Z\\",\\"author\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"},\\"publisher\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"}}]}"]]},"headers":[],"relativePath":"software/waybeam-venc.md","filePath":"software/waybeam-venc.md","lastUpdated":1780228136000}'),r={name:"software/waybeam-venc.md"};function o(s,t,i,d,g,f){return a(),n("div",null,[...t[0]||(t[0]=[l('<h1 id="waybeam-venc-—-відеоенкодер-для-fpv" tabindex="-1">Waybeam venc — Відеоенкодер для FPV <a class="header-anchor" href="#waybeam-venc-—-відеоенкодер-для-fpv" aria-label="Permalink to &quot;Waybeam venc — Відеоенкодер для FPV&quot;">​</a></h1><p><strong>waybeam venc</strong> — це автономний H.265/H.264 відеоенкодер і RTP-стрімер для камер на чіпах SigmaStar Infinity6E (Star6E) та Infinity6C (Maruko). Розроблений спеціально для FPV-дронів із мінімальною затримкою та повним керуванням через HTTP API у реальному часі.</p><div class="info custom-block"><p class="custom-block-title">Репозиторій</p><p><a href="https://github.com/OpenIPC/waybeam_venc" target="_blank" rel="noreferrer">https://github.com/OpenIPC/waybeam_venc</a></p></div><hr><h3 id="можливості" tabindex="-1">Можливості <a class="header-anchor" href="#можливості" aria-label="Permalink to &quot;Можливості&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Функція</th><th style="text-align:left;">Опис</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Кодеки</strong></td><td style="text-align:left;">H.265 (HEVC) та H.264 з режимами CBR / VBR / AVBR / FIXQP</td></tr><tr><td style="text-align:left;"><strong>Стрімінг</strong></td><td style="text-align:left;">RTP-пакетизація; Compact UDP-режим (raw NAL units без заголовків)</td></tr><tr><td style="text-align:left;"><strong>HTTP API</strong></td><td style="text-align:left;">Зміна будь-якого з 84 параметрів в реальному часі без перезапуску потоку</td></tr><tr><td style="text-align:left;"><strong>Веб-панель</strong></td><td style="text-align:left;">Вбудований дешборд на порту 80: конфігурація, API-docs, ISP-тюнінг</td></tr><tr><td style="text-align:left;"><strong>ISP IQ</strong></td><td style="text-align:left;">60+ ISP-параметрів з підтримкою export/import профілів</td></tr><tr><td style="text-align:left;"><strong>Custom 3A</strong></td><td style="text-align:left;">Вбудований AE та AWB з конфігурованими лімітами підсилення та відстеженням</td></tr><tr><td style="text-align:left;"><strong>ROI-кодування</strong></td><td style="text-align:left;">Пріоритет центру кадру для FPV</td></tr><tr><td style="text-align:left;"><strong>Висока частота кадрів</strong></td><td style="text-align:left;">До 120 fps для IMX415 / IMX335</td></tr><tr><td style="text-align:left;"><strong>Аудіо</strong></td><td style="text-align:left;">Захват звуку, кодеки G.711 / PCM / Opus</td></tr><tr><td style="text-align:left;"><strong>Запис на SD</strong></td><td style="text-align:left;">MPEG-TS (HEVC + PCM), безпечний при відключенні живлення</td></tr><tr><td style="text-align:left;"><strong>Gemini-режим</strong></td><td style="text-align:left;">Два VENC-канали: стрімінг + запис незалежно</td></tr><tr><td style="text-align:left;"><strong>Адаптивний бітрейт запису</strong></td><td style="text-align:left;">Авто-зниження бітрейту запису якщо SD-карта не встигає (10%/с)</td></tr><tr><td style="text-align:left;"><strong>EIS (стабілізація)</strong></td><td style="text-align:left;">GyroGlide-Lite — гіроскопна стабілізація (тільки Star6E)</td></tr><tr><td style="text-align:left;"><strong>IMU</strong></td><td style="text-align:left;">Підтримка BMI270 (тільки Star6E)</td></tr></tbody></table><hr><h3 id="підтримувані-чіпи" tabindex="-1">Підтримувані чіпи <a class="header-anchor" href="#підтримувані-чіпи" aria-label="Permalink to &quot;Підтримувані чіпи&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Чіп</th><th style="text-align:left;">Назва</th><th style="text-align:left;">Статус</th></tr></thead><tbody><tr><td style="text-align:left;">SigmaStar Infinity6E</td><td style="text-align:left;">Star6E (SSC338Q та ін.)</td><td style="text-align:left;">✅ Повна підтримка</td></tr><tr><td style="text-align:left;">SigmaStar Infinity6C</td><td style="text-align:left;">Maruko</td><td style="text-align:left;">✅ Повна підтримка</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Star6E та RTP</p><p>На Star6E режим <code>outgoing.streamMode: &quot;rtp&quot;</code> вимагає кодек <code>video0.codec: &quot;h265&quot;</code>. Maruko підтримує обидва кодеки: h264 та h265.</p></div><hr><h3 id="порівняння-з-majestic" tabindex="-1">Порівняння з Majestic <a class="header-anchor" href="#порівняння-з-majestic" aria-label="Permalink to &quot;Порівняння з Majestic&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;"></th><th style="text-align:left;"><strong>waybeam venc</strong></th><th style="text-align:left;"><strong>Majestic</strong></th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Призначення</strong></td><td style="text-align:left;">Спеціалізований FPV-стрімер</td><td style="text-align:left;">Загальна IP-камера</td></tr><tr><td style="text-align:left;"><strong>HTTP API</strong></td><td style="text-align:left;">Повна, реалтаймова зміна всіх полів</td><td style="text-align:left;">Обмежена</td></tr><tr><td style="text-align:left;"><strong>WFB-інтеграція</strong></td><td style="text-align:left;">Нативна через Unix-сокет / UDP</td><td style="text-align:left;">Через UDP</td></tr><tr><td style="text-align:left;"><strong>Запис на SD</strong></td><td style="text-align:left;">Gemini-режим (стрімінг + запис)</td><td style="text-align:left;">Обмежений</td></tr><tr><td style="text-align:left;"><strong>EIS / IMU</strong></td><td style="text-align:left;">GyroGlide-Lite (Star6E)</td><td style="text-align:left;">Немає</td></tr><tr><td style="text-align:left;"><strong>ISP-тюнінг</strong></td><td style="text-align:left;">60+ параметрів в реальному часі</td><td style="text-align:left;">Базовий</td></tr><tr><td style="text-align:left;"><strong>Ліцензія</strong></td><td style="text-align:left;">MIT (відкритий код)</td><td style="text-align:left;">Закритий</td></tr></tbody></table><hr><h3 id="структура-документаціі" tabindex="-1">Структура документації <a class="header-anchor" href="#структура-документаціі" aria-label="Permalink to &quot;Структура документації&quot;">​</a></h3><ul><li><a href="/software/waybeam-venc-install-camera"><strong>Встановлення на камеру</strong></a> — завантаження бінарника, конфігурація <code>/etc/venc.json</code>, перший запуск</li><li><a href="/software/waybeam-venc-install-groundstation"><strong>Інтеграція з WFB-ng</strong></a> — заміна Majestic на venc у зв&#39;язці з WFB-ng</li><li><a href="/software/waybeam-venc-web-interface"><strong>Веб-панель та HTTP API</strong></a> — налаштування через браузер і командний рядок</li></ul>',16)])])}const p=e(r,[["render",o]]);export{y as __pageData,p as default};
